sql:
SELECT title
FROM movies
WHERE release_year = 2000;

SELECT MAX(review_count) AS max_reviews
FROM (
    SELECT movie_id, COUNT(review_id) AS review_count
    FROM reviews
    GROUP BY movie_id
) AS movie_reviews;

SELECT title, rating, num_of_ratings
FROM movies
ORDER BY rating DESC;

SELECT COUNT(DISTINCT user_id) AS num_users_watched
FROM watch_history
WHERE movie_id = 0;

SELECT user_id, movie_id, AVG(rating) AS average_rating, COUNT(rating) AS num_of_ratings
FROM ratings
GROUP BY user_id, movie_id;

SELECT title
FROM movies
WHERE rating = (SELECT MAX(rating) FROM movies);
